local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxMainCtrl:LxBaseCtrl
local LxMainCtrl = classX("LxMainCtrl", LxBaseCtrl)

function LxMainCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxMainCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxMainCtrl:IniEvents()
    self:AddEventHandler(EventNames.GAME_PAUSE_CHANGE, self.OnGamePauseChange, self)
end

function LxMainCtrl:OnGamePauseChange(pause, holdTime)
    if pause then
        if self._isMainInit then
            LxAlarmHelper.SetAlarmForOfflineType()
        end
    end
end

---登录完成后进入场景
function LxMainCtrl:OnEnterAfterLogin()
    self:OnMainInit()

    local opType = nil
    if not CtrlCenter.Story:IsStartPlayed() or  not CtrlCenter.Story:IsStartPlayEnded() then
        local storyType, dataId = CtrlCenter.Story:GetBeginStoryData()
        if storyType > 0 and dataId > 0 then
            opType = 3
        end
    end
    self:GoHome({type = opType}, {loadUIName = UiNames.Loader, isHideReloadNode = true, isHideLoaderMask = true})
end

function LxMainCtrl:GoHome(config, loadParams)
    if MgrCenter.LevelMgr:IsInLevel(LevelNames.Main) then
        return
    end
    config = config or {}
    if not config.mapName then
        config.mapName = "City001"
    end
    loadParams = loadParams or {loadUIName = UiNames.Interlude}
    MgrCenter.LevelMgr:LoadLevel(LevelNames.Main, config, loadParams)
end

function LxMainCtrl:OnMainInit()
    if self._isMainInit then return end
    self._isMainInit = true

    self:IniEvents()

    LxAlarmHelper.Initialize()
end

function LxMainCtrl:OpenRoleUI()
    ShowPanel(UiNames.RoleMain)
end

function LxMainCtrl:OpenBagUI()
    ShowPanel(UiNames.Bag)
end


return LxMainCtrl